int threeSumClosest(int* nums, int numsSize, int target) {
    qsort(nums, numsSize, sizeof(int), cmp);
    int ans = 1 << 30;
    for (int i = 0; i < numsSize; ++i) {
        int j = i + 1, k = numsSize - 1;
        while (j < k) {
            int t = nums[i] + nums[j] + nums[k];
            if (t == target) {
                return t;
            }
